import{_ as o,o as t,c as r,ag as s}from"./chunks/framework.CMYkYJvz.js";const h=JSON.parse('{"title":"Filters","description":"Request and response filter configuration.","frontmatter":{"title":"Filters","description":"Request and response filter configuration.","editLink":false},"headers":[],"relativePath":"en/reference/rules/filters.md","filePath":"en/reference/rules/filters.md"}'),d={name:"en/reference/rules/filters.md"};function n(a,e,c,i,l,u){return t(),r("div",null,[...e[0]||(e[0]=[s(`<blockquote><p>This page is automatically synced from <code>docs-en/rules/filters.md</code>. Language: <strong>English</strong> | <a href="./../../../reference/rules/filters">中文</a></p></blockquote><h1 id="filters" tabindex="-1">Filters <a class="header-anchor" href="#filters" aria-label="Permalink to &quot;Filters&quot;">​</a></h1><p>Filters narrow when a matched rule should execute, using method, header, IP, URL, or path/regex conditions.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>example.com host://127.0.0.1:3000 includeFilter://m:GET</span></span>
<span class="line"><span>example.com host://127.0.0.1:3000 excludeFilter:///admin/</span></span></code></pre></div><p>Use include filters to require a condition and exclude filters to skip a condition.</p><blockquote><p>⚠️ <strong>Several filter prefixes are inert at runtime in 0.0.96 (verified) — do not rely on them:</strong></p><ul><li><strong><code>s:</code> (status) and <code>resH:</code> (response header)</strong> are never evaluated: <code>includeFilter://s:</code> / <code>includeFilter://resH:</code> lock the rule to never apply (even when the status/header actually matches), and <code>excludeFilter://s:</code> / <code>excludeFilter://resH:</code> never exclude. They run in the request phase where the response is not yet known.</li><li><strong><code>h:</code> / <code>reqH:</code> only match standard request headers</strong> (e.g. <code>User-Agent</code>, <code>Accept</code>, <code>Host</code>). <code>Content-Type</code> and custom headers (<code>X-*</code>) are not evaluated — verified <code>h:Content-Type=json</code> and <code>h:X-Custom-Header</code> apply regardless of the actual request, while <code>h:User-Agent=curl</code> works.</li><li><strong><code>b:</code> (body) does not filter.</strong> The documented <code>b:/regex/</code> form is fail-closed on include (rule never matches) and never excludes; a bare <code>b:foo</code> value is ignored.</li></ul><p>Working request-phase filters: <code>m:</code> (method), <code>i:</code> (client IP), <code>/path</code> and <code>/regex/</code> (path), <code>h:</code>/<code>reqH:</code> for standard headers, and host/URL filters. For status/body/response-header filtering use <code>bifrost search</code> instead.</p></blockquote>`,6)])])}const f=o(d,[["render",n]]);export{h as __pageData,f as default};
